INSERT INTO places (content_id, title, addr1, addr2, latitude, longitude, first_image1, first_image2, area_code, district_code, category_code1, category_code2, zipcode, tel, overview) VALUES
('2750144', '가가상점', '충청남도 공주시 감영길 3 (반죽동)', NULL, '36.4528799330097', '127.121658480839', NULL, NULL, '44', '150', 'SH', 'SH05', '32546', NULL, '공주시 원도심에 자리 잡은 가가상점은 공주 지역에서 활동하는 예술가 단체, 화가, 공방들이 기획하고 제작한 로컬 굿즈를 판매하고 있으며, 여행자와 방문자를 위한 추천 도서와 관련 상품들도 판매하고 있다. 굿즈들은 엽서, 스티커, 마스킹테이프, 책갈피, 그립톡 등 다양한 제품이 준비되어 있으며 아기자기한 디자인으로 시간 가는 줄 모르고 구경하게 된다.'),
('2805408', '가가와', '부산광역시 부산진구  중앙번영로 (6)', NULL, '35.1447671591569', '129.059799436643', NULL, NULL, '26', '230', 'FD', 'FD02', '47361', NULL, '부산광역시 부산진구에 위치한 가가와는 돈가스 전문점이다. 100% 수제돈가스로 만들며 얼리지 않은 1등급 생등심만을 사용하고 있다. 방부제를 넣지 않은 최고급 생빵가루를 사용한다. 소스 또한 전통방식을 그대로 직접 제조하여 만들고 있는 돈가스집이다. 돈가스 외에도 우동, 메밀국수 등의 메뉴를 맛볼 수 있으며 다양한 조합의 세트, 정식 메뉴가 준비되어 있다.'),
('2750143', '가가책방', '충청남도 공주시 당간지주길 10 (반죽동)', '(반죽동)', '36.4521187744', '127.1219749520', 'http://tong.visitkorea.or.kr/cms/resource/06/3564906_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/06/3564906_image3_1.jpg', '44', '150', 'VE', 'VE12', '32549', NULL, '가가책방은 2019년 6월 9일 문을 연 공주시 최초의 동네 책방이다. 2020년 코로나 팬데믹 이후 무인으로 운영되고 있다. 책방에 방문하고자 하는 이는 전화 혹은 SNS로 메시지로 비밀번호와 간단한 이용법을 문의해야 한다. 단독 혹은 촬영장 등으로 공간 예약, 이용은 제한된다. 기본적으로 공유 이용 공간이다. 충분히 공간에 만족했거나 좋았다면 입장료 5,000원을 지불할 수 있다. 무인으로 이용되고 있으므로 이용 후 간단한 정리 정돈을 하고 가야 한다.'),
('127480', '가거도', '전라남도 신안군 흑산면 가거도길 38-2', NULL, '34.0520609879', '125.1263860145', 'http://tong.visitkorea.or.kr/cms/resource/28/3572128_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/28/3572128_image3_1.jpg', '46', '910', 'NA', 'NA02', '58866', NULL, '가거도(소흑산도)는 중국의 새벽닭 울음소리가 들릴 만큼 중국 땅과 가깝다는 우리나라 최서남단의 섬으로, 독실산(639m)의 산세가 높고 절벽으로 형성되어 웅장한 절경을 자랑하는 섬이다. 가거도의 섬등반도는 서쪽에 있는 반도 형태의 지형으로 해안선 주변으로 반도 전체가 주상절리를 이루고 있기 때문에 섬등병풍 바위라고도 불린다. 기암절벽으로 이루어진 암봉과 병풍처럼 펼쳐진 해식애가 일대 장관을 이루며, 특히 낙조 경관이 아름답다. 가거도라는 이름은 가히 살만한 섬이라는 뜻에서 붙었다고도 하고, 가도 가도 뱃길의 끝이 보이지 않는 섬이라해서 가거도라 불리었다는 설도 있다. 가거도는 서해안 어업전진기지로서 매우 중요한 섬이다. 한중일 어선들의 각축장이 되어 있는 황금 어장이기도 하고, 국토의 최서남단에 있기에 지리적, 외교적, 정치적으로 중요한 섬이기도 하다. 멸치, 조기, 갈치, 다랑어, 돔 등 온갖 고기들이 모여들기 때문에 연중 많은 낚시객들이 찾는 섬이며, 가거도 등대 앞바다에는 천연기념물인 바닷새의 번식지 국흘도(구굴도)가 있다. 여름철새인 슴새와 뿔쇠오리가 이 무인도에 둥지를 틀고 번식하는 등 백여 종의 철새들이 봄과 가을에 가거도에서 쉬거나 번식을 한다.'),
('1433504', '가경 터미널시장', '충청북도 청주시 흥덕구 가경동', '1438', '36.6286485111', '127.4341171334', 'http://tong.visitkorea.or.kr/cms/resource/50/3492550_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/50/3492550_image3_1.jpg', '43', '113', 'SH', 'SH06', '28398', NULL, '가경터미널시장은 충북 청주시 흥덕구 가경동에 위치한 상설 재래시장이다. 이곳은 상가 주택건물형 소형시장으로 논밭이었던 이곳은 시외버스터미널이 시내로부터 옮겨오면서 발전하여 현재의 상권이 자리 잡게 되었다. 또한 버스터미널과 아파트 신축에 따른 주민의 증가로 가경터미널시장이 1994년부터 자연스럽게 형성되었다. 신선한 채소와 과일, 수산물, 정육, 반찬류 등 다양한 식재료를 합리적인 가격에 구매할 수 있는 것이 특징이다. 다양한 분식과 먹거리들도 풍부하게 마련되어 있어, 청주 시민은 물론 외지 방문객들에게도 인기 있는 먹거리 명소로 자리 잡고 있다.'),
('2901530', '가경목장', '경기도 안산시 상록구 감골로 173 (사동)', NULL, '37.297065419866186', '126.85799003765526', 'https://tong.visitkorea.or.kr/cms/resource/12/2901512_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/12/2901512_image3_1.jpg', '41', '271', 'FD', 'FD01', '15583', NULL, '가경목장은 경기도 안산시 상록구 사동에 있는 고깃집이다. 아들, 딸과 함께 가족 운영을 한다는 뜻으로 상호를 가경목장이라고 정했다. 참숯 직화구이 전문점이다. 대표 메뉴는 두툼한 국내산 삼겹살과 소고기처럼 마블링이 있는 도토리꽃목살이다. 고기와 함께 제공되는 특제 소스인 멸치젓갈 소스에 찍어 먹으면 더욱 맛있게 먹을 수 있다. 부족한 밑반찬은 셀프 코너에서 가져다 먹을 수 있다. 가게 뒤편에 주차할 수 있다. 지하철 수인분당선 사리역 2번 출구에서 716m 떨어져 있어 도보로도 이용할 수 있다.'),
('1797757', '가경식당', '충청남도 부여군 부여읍 성왕로 286', NULL, '36.283298', '126.91894', NULL, NULL, '44', '760', 'FD', 'FD01', '33148', NULL, '부여군에 위치한 가경식당은 직접 농사지은 쌀 및 채소류를 사용하며, 직접 짠 들기름으로 반찬을 제공한다. 예약제로 운영하기 때문에 방문하기 전 예약이 필수이다. 이곳의 메뉴는 두 가지로 홍어찌개와 오리주물럭이다. 든든한 집밥 한끼를 가경식당에서 즐길 수 있다.'),
('126273', '가계해수욕장', '전라남도 진도군 고군면 신비의바닷길 47', '(고군면)', '34.4354594945', '126.3547412438', 'http://tong.visitkorea.or.kr/cms/resource/36/3079736_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/36/3079736_image3_1.jpg', '46', '900', 'NA', 'NA02', '58911', NULL, '바닷물이 갈라지는 현대판 모세의 기적으로 유명한 신비의 바닷길옆에 위치한 해수욕장이다. 넓은 백사장과 다도해상을 마주하고 풍경이 아름다운 해수욕장으로 백사장 길이는 3㎞이다. 교통이 편리할 뿐 아니라 넓은 주차장과 샤워장, 음수대 등 편의시설이 잘 갖추어져 있고 교통이 편리하여 자가용을 이용한 피서객들이 많이 찾는다. 해수욕장 인근에는 조형물들이 있어서 포토존으로 인기가 좋으며 해변가를 따라 소나무와 잔디가 있어 나무아래 그늘에서 햇볕을 피할 수 있고 초록색과 파란 바다색이 어우러져 아름다운 경치를 즐기며 물놀이와 휴식을 즐길 수 있다. 또한, 갯바위와 선착장, 무인도에서 감성동, 도다리, 농어, 숭어, 장어, 보리멸 등의 바다낚시를 즐길 수 있다. 인근에 진도해양생태관, 진도 신비의 바닷길, 금호도 등의 관광지가 있다.'),
('2019720', '가고파 꼬부랑길 벽화마을', '경상남도 창원시 마산합포구 성호서7길 15-8', NULL, '35.2077256624183', '128.569629608494', 'https://tong.visitkorea.or.kr/cms/resource/55/2033255_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/55/2033255_image3_1.jpg', '48', '125', 'VE', 'VE04', '51281', NULL, '가고파 꼬부랑길벽화마을은 2013년 12월 추산동과 성호동 일대 30여 가구를 잇는 골목에 조성됐다. 여행은 벽화마을 안내도가 설치된 성호서10길과 성호서2길이 만나는 지점에서 시작한다. 미국 러시모어산의 큰바위얼굴에 조각가 문신과 천상병 시인 등 창원시와 인연이 있는 예술가의 얼굴을 그려 넣은 벽화가 있어 쉽게 찾을 수 있다.
